// @vitest-environment node
/**
 * SPEC-043: Modelo de datos v3 — migración v2→v3 (empresas globales, contactIds,
 * grupos «General»), encadenado v1→v2→v3, idempotencia del v3, arranque vacío
 * y recuperación de corruptos (comportamiento SPEC-006 intacto).
 * Generated by QA Dev agent.
 *
 * fs real en directorio temporal; initStore(baseDir) inyectable (re-init sobre
 * el mismo baseDir = simulación de reinicio de la app, patrón store.test.ts).
 */
import { existsSync, mkdtempSync, readdirSync, readFileSync, writeFileSync } from 'fs'
import { tmpdir } from 'os'
import { join } from 'path'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { getStatus, initStore, type DbData } from '../../../src/main/db/store'
import type { Interview, InterviewGroup } from '../../../src/renderer/src/types/domain'

vi.mock('electron', () => ({
  app: {
    getPath: (): string => {
      throw new Error('app.getPath no debe usarse en tests: initStore recibe baseDir inyectado')
    }
  }
}))

const NOW = '2026-07-01T09:00:00.000Z'
const UUID_V4 = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[0-9a-f]{4}-[0-9a-f]{12}$/

let baseDir = ''
let dbPath = ''

function readDbFile(): DbData {
  return JSON.parse(readFileSync(dbPath, 'utf-8')) as DbData
}

/** Entrevista con la forma v2 (contactId único, sin contactIds ni grupo). */
function interviewV2(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    id: 'i-1',
    discoveryId: 'd-1',
    companyId: 'c-1',
    contactId: null,
    templateId: null,
    title: 'Entrevista v2',
    status: 'draft',
    scriptMarkdown: null,
    objectives: [],
    wavPath: null,
    transcriptPath: null,
    createdAt: NOW,
    updatedAt: NOW,
    ...overrides
  }
}

/** Almacén v2 completo (7 colecciones base) con overrides por colección. */
function dbV2(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    schemaVersion: 2,
    discoveries: [{ id: 'd-1', name: 'Vertical Sanidad', createdAt: NOW, updatedAt: NOW }],
    companies: [
      {
        id: 'c-1',
        discoveryId: 'd-1',
        name: 'Acme Corp',
        website: 'https://acme.example',
        linkedinUrl: null,
        context: 'Contexto de Acme',
        createdAt: NOW,
        updatedAt: NOW
      }
    ],
    contacts: [
      {
        id: 'ct-1',
        companyId: 'c-1',
        name: 'Jane Doe',
        position: 'CTO',
        linkedinUrl: null,
        context: null,
        createdAt: NOW,
        updatedAt: NOW
      }
    ],
    interviewTemplates: [],
    interviews: [interviewV2()],
    noteTemplates: [],
    notes: [],
    ...overrides
  }
}

beforeEach(() => {
  baseDir = mkdtempSync(join(tmpdir(), 'maurya-migration-'))
  dbPath = join(baseDir, 'db.json')
})

describe('store (SPEC-043 migración v3)', () => {
  describe('v2 to v3 migration', () => {
    // SPEC-043 · AC-27
    it('migrates a v2 store atomically to v3: companies lose discoveryId without dedup and interviews turn contactId into contactIds without the old field', () => {
      writeFileSync(
        dbPath,
        JSON.stringify(
          dbV2({
            companies: [
              {
                id: 'c-1',
                discoveryId: 'd-1',
                name: 'Acme Corp',
                website: 'https://acme.example',
                linkedinUrl: null,
                context: 'Contexto de Acme',
                createdAt: NOW,
                updatedAt: NOW
              },
              // Mismo nombre en otro discovery: NO se deduplica
              {
                id: 'c-2',
                discoveryId: 'd-2',
                name: 'Acme Corp',
                website: null,
                linkedinUrl: null,
                createdAt: NOW,
                updatedAt: NOW
              }
            ],
            interviews: [
              interviewV2({ id: 'i-with', contactId: 'ct-1' }),
              interviewV2({ id: 'i-without', contactId: null })
            ]
          })
        )
      )

      initStore(baseDir)

      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      // Empresas: sin discoveryId, resto de campos intactos, SIN deduplicar
      expect(persisted.companies).toHaveLength(2)
      for (const company of persisted.companies) {
        expect(company).not.toHaveProperty('discoveryId')
      }
      expect(persisted.companies[0].name).toBe('Acme Corp')
      expect(persisted.companies[0].website).toBe('https://acme.example')
      expect(persisted.companies[0].context).toBe('Contexto de Acme')
      expect(persisted.companies[1].name).toBe('Acme Corp')
      // Entrevistas: contactIds = [contactId] (o vacío) y sin campo contactId
      const withContact = persisted.interviews.find((item) => item.id === 'i-with') as Interview
      const withoutContact = persisted.interviews.find(
        (item) => item.id === 'i-without'
      ) as Interview
      expect(withContact.contactIds).toEqual(['ct-1'])
      expect(withoutContact.contactIds).toEqual([])
      expect(withContact).not.toHaveProperty('contactId')
      expect(withoutContact).not.toHaveProperty('contactId')
      // Discovery: gana objectives null (backfill)
      expect(persisted.discoveries[0].objectives).toBeNull()
    })

    // SPEC-043 · AC-28
    it('creates exactly one «General» group per discovery WITH interviews assigning them all, and none for discoveries without interviews', () => {
      writeFileSync(
        dbPath,
        JSON.stringify(
          dbV2({
            discoveries: [
              { id: 'd-1', name: 'Con entrevistas', createdAt: NOW, updatedAt: NOW },
              { id: 'd-empty', name: 'Sin entrevistas', createdAt: NOW, updatedAt: NOW }
            ],
            interviews: [
              interviewV2({ id: 'i-1' }),
              interviewV2({ id: 'i-2', title: 'Segunda entrevista' })
            ]
          })
        )
      )

      initStore(baseDir)

      const persisted = readDbFile()
      // Exactamente UN grupo «General», solo para el discovery con entrevistas
      expect(persisted.interviewGroups).toHaveLength(1)
      const general = persisted.interviewGroups[0] as InterviewGroup
      expect(general.id).toMatch(UUID_V4)
      expect(general.discoveryId).toBe('d-1')
      expect(general.name).toBe('General')
      expect(general.objective).toBeNull()
      expect(general.interviewTemplateId).toBeNull()
      expect(general.noteTemplateId).toBeNull()
      // Todas las entrevistas del discovery quedan asignadas a ese grupo
      for (const interview of persisted.interviews) {
        expect(interview.interviewGroupId).toBe(general.id)
      }
    })

    // SPEC-043 · AC-29
    it('preserves optional settings singletons and optional interview fields intact through the migration', () => {
      const aiUsage = { calls: 3, inputTokens: 1200, outputTokens: 400, estimatedCostUsd: 0.34 }
      const objectiveResults = [{ achieved: true, reason: 'Se validó el dolor' }]
      const objectiveOverrides = [{ achieved: false, note: 'Marcado a mano' }]
      const questionOutcomes = [{ question: '¿Cuánto cuesta?', outcome: 'discarded' }]
      writeFileSync(
        dbPath,
        JSON.stringify(
          dbV2({
            interviews: [
              interviewV2({ aiUsage, objectiveResults, objectiveOverrides, questionOutcomes })
            ],
            aiCostSettings: { limitUsd: 5 },
            assistantSettings: { queueSize: 4 },
            customPrompts: [
              { id: 'script-generation', body: 'Prompt personalizado', updatedAt: NOW }
            ],
            linkedinMcpSettings: { url: 'https://mcp.example/linkedin' }
          })
        )
      )

      initStore(baseDir)

      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      // Settings singleton intactos
      expect(persisted.aiCostSettings).toEqual({ limitUsd: 5 })
      expect(persisted.assistantSettings).toEqual({ queueSize: 4 })
      expect(persisted.customPrompts).toEqual([
        { id: 'script-generation', body: 'Prompt personalizado', updatedAt: NOW }
      ])
      expect(persisted.linkedinMcpSettings).toEqual({ url: 'https://mcp.example/linkedin' })
      // Campos opcionales de la entrevista intactos
      const interview = persisted.interviews[0]
      expect(interview.aiUsage).toEqual(aiUsage)
      expect(interview.objectiveResults).toEqual(objectiveResults)
      expect(interview.objectiveOverrides).toEqual(objectiveOverrides)
      expect(interview.questionOutcomes).toEqual(questionOutcomes)
    })
  })

  describe('v1 chained migration', () => {
    // SPEC-043 · AC-30
    it('chains v1 to v2 to v3 producing a valid v3 store from a v1 file', () => {
      // v1: las entrevistas NO tienen discoveryId (se backfillea desde su empresa)
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { discoveryId, ...v1Interview } = interviewV2({ contactId: 'ct-1' })
      writeFileSync(dbPath, JSON.stringify(dbV2({ schemaVersion: 1, interviews: [v1Interview] })))

      initStore(baseDir)

      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      // v1→v2: backfill del discovery desde la empresa de la entrevista
      expect(persisted.interviews[0].discoveryId).toBe('d-1')
      // v2→v3: contactIds, grupo «General» y empresa global
      expect(persisted.interviews[0].contactIds).toEqual(['ct-1'])
      expect(persisted.interviews[0]).not.toHaveProperty('contactId')
      expect(persisted.interviewGroups).toHaveLength(1)
      expect(persisted.interviews[0].interviewGroupId).toBe(persisted.interviewGroups[0].id)
      expect(persisted.companies[0]).not.toHaveProperty('discoveryId')
      expect(persisted.discoveries[0].objectives).toBeNull()
      expect(getStatus()).toEqual({ ready: true, initError: null })
    })
  })

  describe('v3 idempotence', () => {
    // SPEC-043 · AC-31
    it('loads an already-v3 file as is without re-migrating nor writing additional «General» groups', () => {
      // Se obtiene un v3 real migrando un v2 y se captura el archivo resultante
      writeFileSync(dbPath, JSON.stringify(dbV2()))
      initStore(baseDir)
      const migratedBytes = readFileSync(dbPath, 'utf-8')
      expect(readDbFile().interviewGroups).toHaveLength(1)

      // Reinicio de la app sobre el v3: se carga tal cual, cero reescrituras
      initStore(baseDir)

      expect(readFileSync(dbPath, 'utf-8')).toBe(migratedBytes)
      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      expect(persisted.interviewGroups).toHaveLength(1)
      expect(getStatus()).toEqual({ ready: true, initError: null })
    })
  })

  describe('fresh store', () => {
    // SPEC-043 · AC-32
    it('creates an empty v3 store with the interviewGroups collection present when there is no data file', () => {
      initStore(baseDir)

      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      expect(persisted.interviewGroups).toEqual([])
      expect(persisted.discoveries).toEqual([])
      expect(persisted.companies).toEqual([])
      expect(getStatus()).toEqual({ ready: true, initError: null })
    })
  })

  describe('corrupt file recovery (SPEC-006 intacto)', () => {
    // SPEC-043 · AC-33
    it('keeps a corrupt file as .corrupt-<ts>, starts an empty v3 store and exposes the error through getStatus()', () => {
      const garbage = '{esto no es json válido «💥»'
      writeFileSync(dbPath, garbage)

      expect(() => initStore(baseDir)).not.toThrow()

      // Error tipado consultable (patrón SPEC-006)
      const status = getStatus()
      expect(status.ready).toBe(true)
      expect(status.initError?.kind).toBe('storage')
      // El archivo dañado se conserva renombrado con sufijo .corrupt-<timestamp>
      const corruptFiles = readdirSync(baseDir).filter((name) =>
        /^db\.json\.corrupt-\d+$/.test(name)
      )
      expect(corruptFiles).toHaveLength(1)
      expect(readFileSync(join(baseDir, corruptFiles[0]), 'utf-8')).toBe(garbage)
      // Y el almacén nuevo es un v3 vacío con interviewGroups presente
      expect(existsSync(dbPath)).toBe(true)
      const persisted = readDbFile()
      expect(persisted.schemaVersion).toBe(3)
      expect(persisted.interviewGroups).toEqual([])
    })

    // SPEC-043 · AC-33 (refuerzo: estructura inválida — v3 declarado sin la
    // colección interviewGroups — sigue el mismo camino de recuperación)
    it('treats a v3 file without the interviewGroups collection as invalid structure and recovers with an empty v3 store', () => {
      const invalid = JSON.stringify({ ...dbV2(), schemaVersion: 3 })
      writeFileSync(dbPath, invalid)

      expect(() => initStore(baseDir)).not.toThrow()

      expect(getStatus().initError?.kind).toBe('storage')
      const corruptFiles = readdirSync(baseDir).filter((name) =>
        /^db\.json\.corrupt-\d+$/.test(name)
      )
      expect(corruptFiles).toHaveLength(1)
      expect(readDbFile().interviewGroups).toEqual([])
    })
  })
})
